/* BTTooltipPaginationStep — PaginationStep / pagination-step balloon.
   Figma: node 2157-1726 (Playground instance with full PaginationStep).
   Figma pagination step variants: node 478-2463.
   All colours via @btech/tokens CSS vars — no hex fallbacks (CLAUDE.md §6). */

/* ── Outer wrapper (arrow + body stacked or side-by-side) ── */

.bt-tooltip-step {
  display: inline-flex;
  flex-direction: column; /* default: top arrow */
  width: 320px;
  max-width: calc(100vw - 32px);
}

.bt-tooltip-step--top    { flex-direction: column-reverse; } /* body on top, arrow below  */
.bt-tooltip-step--bottom { flex-direction: column; }          /* arrow on top, body below  */
.bt-tooltip-step--left   { flex-direction: row-reverse; align-items: flex-start; width: auto; }
.bt-tooltip-step--right  { flex-direction: row;         align-items: flex-start; width: auto; }

/* ── Arrow row / col ──────────────────────────────────────────────────────────
   Arrow position is driven by the CSS custom property --bt-arrow-offset:
     • horizontal (top/bottom): px from the balloon's left edge to arrow centre
     • vertical   (left/right): px from the balloon's top  edge to arrow centre

   Default values come from the arrowPosition modifier class (enum-to-px map).
   The parent showcase can override by setting an arrowOffset prop, which the
   component applies as an inline style (inline > class specificity).         */

/* Enum-based fallback values ─────────────────────────────────────────────── */
.bt-tooltip-step__arrow-row--left      { --bt-arrow-offset: 24px; }
.bt-tooltip-step__arrow-row--left-mid  { --bt-arrow-offset: 25%; }
.bt-tooltip-step__arrow-row--mid       { --bt-arrow-offset: 50%; }
.bt-tooltip-step__arrow-row--right-mid { --bt-arrow-offset: 75%; }
.bt-tooltip-step__arrow-row--right     { --bt-arrow-offset: calc(100% - 24px); }

.bt-tooltip-step__arrow-col--left      { --bt-arrow-offset: 24px; }
.bt-tooltip-step__arrow-col--left-mid  { --bt-arrow-offset: 25%; }
.bt-tooltip-step__arrow-col--mid       { --bt-arrow-offset: 50%; }
.bt-tooltip-step__arrow-col--right-mid { --bt-arrow-offset: 75%; }
.bt-tooltip-step__arrow-col--right     { --bt-arrow-offset: calc(100% - 24px); }

/* Horizontal arrow wrapper (top / bottom) */
.bt-tooltip-step__arrow-row {
  position: relative;
  width: 320px;
  max-width: calc(100vw - 32px);
  height: 8px;
  flex-shrink: 0;
}

.bt-tooltip-step__arrow-row .bt-tooltip-step__arrow {
  position: absolute;
  left: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* Vertical arrow wrapper (left / right) */
.bt-tooltip-step__arrow-col {
  position: relative;
  width: 8px;
  flex-shrink: 0;
  align-self: stretch;
}

.bt-tooltip-step__arrow-col .bt-tooltip-step__arrow {
  position: absolute;
  top: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* ── Body card ── */

.bt-tooltip-step__body {
  background: var(--bg-inverse);
  border-radius: var(--radius-sm);
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  width: 320px;
  max-width: calc(100vw - 32px);
  box-sizing: border-box;
}

.bt-tooltip-step--left  .bt-tooltip-step__body,
.bt-tooltip-step--right .bt-tooltip-step__body {
  width: max-content;
  min-width: 250px;
  max-width: 320px;
}

/* ── Header row (label + close button) ── */

.bt-tooltip-step__header {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  width: 100%;
}

.bt-tooltip-step__label {
  flex: 1;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-md);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-inverse);
  margin: 0;
}


/* ── Description ── */

.bt-tooltip-step__description {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-inverse);
  margin: 0;
}

/* ── Footer row (step label + navigation buttons) ── */

.bt-tooltip-step__footer {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  width: 100%;
}

/* Centered variant — everything centred, no step text on left */
.bt-tooltip-step__footer--centered {
  justify-content: center;
  gap: var(--space-md);
}

.bt-tooltip-step__step-label {
  flex: 1;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-inverse);
  margin: 0;
}

/* Step label in centered variant — no flex */
.bt-tooltip-step__footer--centered .bt-tooltip-step__step-label {
  flex: none;
}

/* Close icon — bare 24px svg, no wrapper styling */
.bt-tooltip-step__close {
  display: inline-flex;
  width: 24px;
  height: 24px;
  padding: 0;
  background: transparent;
  border: none;
  color: var(--text-inverse);
  cursor: pointer;
  flex-shrink: 0;
}

/* RTL — flip chevron icons in centered variant */
[dir="rtl"] .bt-tooltip-step__footer--centered svg {
  transform: scaleX(-1);
}

/**
 * BTTooltipPaginationStep — PaginationStep / pagination-step balloon.
 *
 * Figma: https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=478-2463
 *
 * @example
 * ```tsx
 * <BTTooltipPaginationStep
 *   label="Fitur Baru"
 *   description="Klik tombol ini untuk memulai."
 *   stepLabel="Step 1 of 3"
 *   stepVariant="button"
 *   hasClose
 *   prevLabel="Kembali"
 *   nextLabel="Selanjutnya"
 *   position="bottom"
 *   onPrev={goPrev}
 *   onNext={goNext}
 *   onClose={endTour}
 * />
 * ```
 */
import { type ReactNode, type CSSProperties } from 'react';
import type {
  BTTooltipPaginationStepVariant,
  BTTooltipPaginationStepPosition,
  BTTooltipPaginationStepArrowPosition,
} from './BTTooltipPaginationStep.types';
import './BTTooltipPaginationStep.css';
import { BTButton } from '../button/BTButton';
import { BTButtonLink } from '../button-link/BTButtonLink';

export interface BTTooltipPaginationStepReactProps {
  label?: string;
  description: string;
  stepLabel?: string;
  stepVariant?: BTTooltipPaginationStepVariant;
  hasClose?: boolean;
  prevLabel?: string;
  nextLabel?: string;
  position?: BTTooltipPaginationStepPosition;
  arrowPosition?: BTTooltipPaginationStepArrowPosition;
  /**
   * Optional dynamic arrow offset (e.g. "120px") — overrides the
   * arrowPosition enum when provided.  Used by PaginationStep overlays that
   * compute the exact trigger-centre distance after viewport clamping.
   */
  arrowOffset?: string;
  /** Rich content rendered between description and footer. */
  children?: ReactNode;
  onPrev?: () => void;
  onNext?: () => void;
  onClose?: () => void;
}

function getArrowPath(position: BTTooltipPaginationStepPosition): string {
  switch (position) {
    case 'bottom': return 'M0 8 L7 1 Q8 0 9 1 L16 8 Z';
    case 'left':   return 'M0 0 L7 7 Q8 8 7 9 L0 16 Z';
    case 'right':  return 'M8 0 L1 7 Q0 8 1 9 L8 16 Z';
    case 'top':
    default:       return 'M0 0 L7 7 Q8 8 9 7 L16 0 Z';
  }
}

export function BTTooltipPaginationStep({
  label,
  description,
  stepLabel,
  stepVariant = 'button',
  hasClose = false,
  prevLabel = 'Prev',
  nextLabel = 'Next',
  position = 'top',
  arrowPosition = 'mid',
  arrowOffset,
  children,
  onPrev,
  onNext,
  onClose,
}: BTTooltipPaginationStepReactProps) {
  const isHorizontal = position === 'left' || position === 'right';
  const arrowPath = getArrowPath(position);
  const arrowViewBox = isHorizontal ? '0 0 8 16' : '0 0 16 8';
  const arrowW = isHorizontal ? 8 : 16;
  const arrowH = isHorizontal ? 16 : 8;
  const hasHeader = !!(label || hasClose);
  const hasFooter = !!(stepLabel || stepVariant);

  const arrowSvg = (
    <svg className="bt-tooltip-step__arrow" width={arrowW} height={arrowH} viewBox={arrowViewBox} fill="none" aria-hidden="true">
      <path d={arrowPath} fill="var(--bg-inverse)" />
    </svg>
  );

  const arrowRowClass = `bt-tooltip-step__arrow-row bt-tooltip-step__arrow-row--${arrowPosition}`;
  const arrowColClass = `bt-tooltip-step__arrow-col bt-tooltip-step__arrow-col--${arrowPosition}`;

  return (
    <div
      className={`bt-tooltip-step bt-tooltip-step--${position}`}
      role="dialog"
      aria-modal={false}
    >
      {/* Arrow — arrowOffset prop overrides enum-based --bt-arrow-offset */}
      {!isHorizontal ? (
        <div
          className={arrowRowClass}
          style={arrowOffset ? { '--bt-arrow-offset': arrowOffset } as CSSProperties : undefined}
        >
          {arrowSvg}
        </div>
      ) : (
        <div
          className={arrowColClass}
          style={arrowOffset ? { '--bt-arrow-offset': arrowOffset } as CSSProperties : undefined}
        >
          {arrowSvg}
        </div>
      )}

      {/* Body card */}
      <div className="bt-tooltip-step__body">
        {/* Header */}
        {hasHeader && (
          <div className="bt-tooltip-step__header">
            {label && <p className="bt-tooltip-step__label">{label}</p>}
            {!label && hasClose && <div style={{ flex: 1 }} />}
            {hasClose && (
              <button
                type="button"
                className="bt-tooltip-step__close"
                aria-label="Tutup"
                onClick={onClose}
              >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" aria-hidden="true">
                  <path
                    d="M18 6L6 18M6 6l12 12"
                    stroke="currentColor"
                    strokeWidth="2"
                    strokeLinecap="round"
                  />
                </svg>
              </button>
            )}
          </div>
        )}

        {/* Description */}
        <p className="bt-tooltip-step__description">{description}</p>

        {/* Rich content slot */}
        {children}

        {/* Footer */}
        {hasFooter && (
          <div
            className={`bt-tooltip-step__footer${
              stepVariant === 'centered' ? ' bt-tooltip-step__footer--centered' : ''
            }`}
          >
            {/* ── button variant ── */}
            {stepVariant === 'button' && (
              <>
                {stepLabel && (
                  <p className="bt-tooltip-step__step-label">{stepLabel}</p>
                )}
                <div style={{ display: 'flex', gap: 8, flexShrink: 0 }}>
                  <BTButton size="small" variant="secondary-light" label={prevLabel} onClick={onPrev} />
                  <BTButton size="small" variant="secondary-light" label={nextLabel} onClick={onNext} />
                </div>
              </>
            )}

            {/* ── link variant ── */}
            {stepVariant === 'link' && (
              <>
                {stepLabel && (
                  <p className="bt-tooltip-step__step-label">{stepLabel}</p>
                )}
                <div style={{ display: 'flex', gap: 12, flexShrink: 0 }}>
                  <BTButtonLink label={prevLabel} variant="secondary" onClick={onPrev} />
                  <BTButtonLink label={nextLabel} variant="primary" onClick={onNext} />
                </div>
              </>
            )}

            {/* ── centered variant ── */}
            {stepVariant === 'centered' && (
              <>
                <BTButton
                  iconOnly
                  variant="primary"
                  size="small"
                  aria-label="Sebelumnya"
                  onClick={onPrev}
                >
                  <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                    <path d="M10 12L6 8l4-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </BTButton>
                {stepLabel && (
                  <p className="bt-tooltip-step__step-label">{stepLabel}</p>
                )}
                <BTButton
                  iconOnly
                  variant="primary"
                  size="small"
                  aria-label="Selanjutnya"
                  onClick={onNext}
                >
                  <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                    <path d="M6 12l4-4-4-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </BTButton>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * BTTooltipPaginationStep — type definitions shared between Vue and React.
 * PaginationStep / pagination-step tooltip balloon.
 * Figma: https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=478-2463
 */

/** Navigation button style inside the step footer. */
export type BTTooltipPaginationStepVariant = 'button' | 'link' | 'centered';

/** Which side the arrow caret appears on. */
export type BTTooltipPaginationStepPosition = 'top' | 'bottom' | 'left' | 'right';

/** Arrow offset along its axis (same semantics as BTTooltipArrowPosition). */
export type BTTooltipPaginationStepArrowPosition =
  | 'left'
  | 'left-mid'
  | 'mid'
  | 'right-mid'
  | 'right';

export interface BTTooltipPaginationStepProps {
  /** Bold title shown at the top of the card. Hidden when omitted. */
  label?: string;
  /** Main description text. Required. */
  description: string;
  /** Step indicator text, e.g. "Step 1 of 5". Hidden when omitted. */
  stepLabel?: string;
  /**
   * Navigation button style.
   * - `button` (default) — secondary rounded buttons (Prev / Next).
   * - `link` — text-link buttons (grey Prev / blue Next).
   * - `centered` — icon-only chevron buttons flanking the step label.
   */
  stepVariant?: BTTooltipPaginationStepVariant;
  /**
   * Show a × close button in the top-right corner.
   * Clicking it fires `@close` / `onClose`. @default false
   */
  hasClose?: boolean;
  /** Prev button label. @default 'Prev' */
  prevLabel?: string;
  /** Next button label. @default 'Next' */
  nextLabel?: string;
  /** Which side the arrow caret renders on. @default 'top' */
  position?: BTTooltipPaginationStepPosition;
  /** Arrow offset along the axis. @default 'mid' */
  arrowPosition?: BTTooltipPaginationStepArrowPosition;
}

export { BTTooltipPaginationStep } from './BTTooltipPaginationStep';
export type {
  BTTooltipPaginationStepReactProps,
} from './BTTooltipPaginationStep';
export type {
  BTTooltipPaginationStepProps,
  BTTooltipPaginationStepVariant,
  BTTooltipPaginationStepPosition,
  BTTooltipPaginationStepArrowPosition,
} from './BTTooltipPaginationStep.types';
